import{_ as e,o as i,c as a,ao as s}from"./chunks/framework.C3EQGe-O.js";const p=JSON.parse('{"title":"runs.csv — your run videos","description":"","frontmatter":{},"headers":[],"relativePath":"runs.md","filePath":"runs.md","lastUpdated":null}'),o={name:"runs.md"};function r(n,t,d,l,c,h){return i(),a("div",null,[...t[0]||(t[0]=[s(`<h1 id="runs.csv-—-your-run-videos" tabindex="-1">runs.csv — your run videos <a class="header-anchor" href="#runs.csv-—-your-run-videos" aria-label="Permalink to &quot;runs.csv — your run videos {#runs.csv-—-your-run-videos}&quot;">​</a></h1><p><code>runs.csv</code> describes your <strong>runs</strong>: the videos of an animal (or any other target) moving through the arena. One row per run video. (A run split across multiple video files uses several rows — see <a href="/Fromage.jl/dev/runs#Runs-that-span-multiple-videos">Runs that span multiple videos</a> below.)</p><p>Not sure about the general formatting rules (timestamps, coordinates, blank cells)? See <a href="/Fromage.jl/dev/data-folder#Rules-both-csv-files-share">the data folder</a> first.</p><h2 id="Required-columns" tabindex="-1">Required columns <a class="header-anchor" href="#Required-columns" aria-label="Permalink to &quot;Required columns {#Required-columns}&quot;">​</a></h2><p>Only two columns must always be there:</p><table tabindex="0"><thead><tr><th style="text-align:right;">column</th><th style="text-align:right;">description</th></tr></thead><tbody><tr><td style="text-align:right;"><code>file</code></td><td style="text-align:right;">the video file name, including its extension (e.g. <code>beetle01.mp4</code>).</td></tr><tr><td style="text-align:right;"><code>calibration_id</code></td><td style="text-align:right;">which calibration to use for this run — must match a <code>calibration_id</code> in <code>calibs.csv</code>.</td></tr></tbody></table><p>A minimal <code>runs.csv</code> can be just:</p><div class="language-csv vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">csv</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">file,</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">calibration_id</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">beetle01.mp4,</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">morning</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">beetle02.mp4,</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">morning</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">beetle03.mp4,</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">afternoon</span></span></code></pre></div><h2 id="Optional-columns" tabindex="-1">Optional columns <a class="header-anchor" href="#Optional-columns" aria-label="Permalink to &quot;Optional columns {#Optional-columns}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">column</th><th style="text-align:right;">default</th><th style="text-align:right;">description</th></tr></thead><tbody><tr><td style="text-align:right;"><code>start</code></td><td style="text-align:right;"><code>0</code></td><td style="text-align:right;">timestamp where the run starts in the video.</td></tr><tr><td style="text-align:right;"><code>stop</code></td><td style="text-align:right;">full duration</td><td style="text-align:right;">timestamp where the run ends.</td></tr><tr><td style="text-align:right;"><code>target_width</code></td><td style="text-align:right;"><code>25</code></td><td style="text-align:right;">the full width (diameter, not radius) of the target, in pixels. <strong>The single most important tuning parameter</strong> — measure it in a paused frame.</td></tr><tr><td style="text-align:right;"><code>start_location</code></td><td style="text-align:right;">see <a href="/Fromage.jl/dev/runs#Where-the-tracker-starts-looking">below</a></td><td style="text-align:right;"><code>&quot;(x, y)&quot;</code> pixel coordinate of the target at <code>start</code>.</td></tr><tr><td style="text-align:right;"><code>darker_target</code></td><td style="text-align:right;"><code>true</code></td><td style="text-align:right;"><code>true</code> if the target is darker than its background, <code>false</code> if lighter.</td></tr><tr><td style="text-align:right;"><code>window_size</code></td><td style="text-align:right;">computed</td><td style="text-align:right;">the size of the search window the tracker scans around the target&#39;s last known position: a single number for a square window (e.g. <code>41</code>) or <code>&quot;(w, h)&quot;</code> for a rectangle. Must be comfortably larger than <code>target_width</code> plus however far the target can move between consecutive frames. The default is computed from <code>target_width</code> and a conservative speed estimate, and is usually fine.</td></tr><tr><td style="text-align:right;"><code>fps</code></td><td style="text-align:right;">video&#39;s frame rate</td><td style="text-align:right;">how many frames per second to track. Lower it for slow targets to speed things up. Cannot exceed the video&#39;s own frame rate.</td></tr><tr><td style="text-align:right;"><code>initial_search_factor</code></td><td style="text-align:right;"><code>4</code></td><td style="text-align:right;">when no start location is known at all, the target is searched for in a window of size <code>min(width, height) / initial_search_factor</code> centered on the frame. Larger values → smaller initial search window.</td></tr><tr><td style="text-align:right;"><code>scale</code></td><td style="text-align:right;"><code>1</code></td><td style="text-align:right;">spatial downsampling factor (0 &lt; scale ≤ 1) applied before tracking; e.g. <code>0.5</code> tracks on half-resolution frames (faster). Returned coordinates are always in original-resolution pixels. The scaled target (<code>target_width × scale</code>) must remain at least 1 pixel wide.</td></tr><tr><td style="text-align:right;"><code>background_length</code></td><td style="text-align:right;"><code>250</code></td><td style="text-align:right;">how many tracked frames form the rolling background model the target is detected against. Counted at the tracking <code>fps</code>, so the model spans <code>background_length / fps</code> seconds; memory scales with it. <code>0</code> disables background subtraction entirely — fine for clean, high-contrast scenes (and much lighter on memory), but static dark marks then compete with the target. Must be <code>0</code> or at least <code>25</code>.</td></tr><tr><td style="text-align:right;"><code>run_id</code></td><td style="text-align:right;">row number</td><td style="text-align:right;">identifies the run; only needed for multi-video runs (below). All-or-nothing: either every row has a <code>run_id</code>, or none does.</td></tr><tr><td style="text-align:right;"><code>path</code></td><td style="text-align:right;"><code>.</code></td><td style="text-align:right;">folder containing <code>file</code>, relative to the location of the csv file.</td></tr><tr><td style="text-align:right;"><code>comment</code></td><td style="text-align:right;">—</td><td style="text-align:right;">free text, ignored.</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Note</p><p>The <code>white_point</code> column is accepted for compatibility but currently has <strong>no effect</strong>. AprilTag drone tracking is configured entirely from <code>calibs.csv</code> — see <a href="/Fromage.jl/dev/calibs#Columns-for-type-apriltag"><code>type = apriltag</code></a> — so <code>runs.csv</code> has no <code>apriltags</code> column.</p></div><div class="tip custom-block"><p class="custom-block-title">The one parameter worth measuring: <code>target_width</code></p><p>Pause a run video on a frame where the animal is clearly visible, and measure how many pixels wide it is (many image viewers let you draw a selection box and read off its size). If the tracker keeps losing your animal, a wrong <code>target_width</code> is the first thing to check.</p></div><h2 id="Where-the-tracker-starts-looking" tabindex="-1">Where the tracker starts looking <a class="header-anchor" href="#Where-the-tracker-starts-looking" aria-label="Permalink to &quot;Where the tracker starts looking {#Where-the-tracker-starts-looking}&quot;">​</a></h2><p>The starting position for a run is determined by the first available of: 2. <code>start_location</code> in <code>runs.csv</code>,</p><ol start="3"><li><p>the <code>center</code> of the run&#39;s calibration in <code>calibs.csv</code>,</p></li><li><p>nothing — the target is searched for near the center of the frame, within a window of <code>min(width, height) / initial_search_factor</code> pixels.</p></li></ol><h2 id="Runs-that-span-multiple-videos" tabindex="-1">Runs that span multiple videos <a class="header-anchor" href="#Runs-that-span-multiple-videos" aria-label="Permalink to &quot;Runs that span multiple videos {#Runs-that-span-multiple-videos}&quot;">​</a></h2><p>If a single run was recorded across several consecutive video files (e.g. the camera splits long recordings), give all its rows the <strong>same <code>run_id</code></strong>, one row per video file, in chronological order:</p><div class="language-csv vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">csv</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">run_id,</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">calibration_id,</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">file,</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">start,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">stop,</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">start_location</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">long,</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">afternoon,</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">beetle03_a.mp4,</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">0,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">,</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">&quot;(210, 400)&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">long,</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">afternoon,</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">beetle03_b.mp4,</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">0,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">00:01:03,</span></span></code></pre></div><ul><li><p><code>file</code>, <code>start</code>, <code>stop</code>, and <code>start_location</code> are per segment; all other parameters (<code>target_width</code>, <code>fps</code>, <code>calibration_id</code>, …) must be identical across the segments of one run, and all segments must come from the same camera setup (same frame size).</p></li><li><p>Leave <code>start_location</code> blank on the second segment onwards: tracking continues from where the previous segment ended.</p></li><li><p><code>run_id</code> is all-or-nothing: as soon as one row has a <code>run_id</code>, every row needs one (rows with a <code>run_id</code> all of their own are ordinary single-video runs). If no row has one, each row is its own run.</p></li></ul><h2 id="Next" tabindex="-1">Next <a class="header-anchor" href="#Next" aria-label="Permalink to &quot;Next {#Next}&quot;">​</a></h2><ul><li><p><a href="./calibs">calibs.csv →</a></p></li><li><p><a href="./results">Your results →</a></p></li></ul>`,21)])])}const u=e(o,[["render",r]]);export{p as __pageData,u as default};
